graphql.query:
query GetGeoEvent($id: Int!) {
  geoEvent(id: $id) {
    id
    latitude
    longitude
    eventType
    platform
    recordedAt
    createdAt
  }
}

query ListGeoEvents($eventType: String, $userId: String, $limit: Int, $offset: Int) {
  geoEvents(
    eventType: $eventType
    userId: $userId
    limit: $limit
    offset: $offset
  ) {
    id
    latitude
    longitude
    eventType
    platform
    deviceModel
    recordedAt
  }
}

mutation CreateGeoEvent($input: GeoEventInput!) {
  createGeoEvent(input: $input) {
    id
    latitude
    longitude
    eventType
    platform
    deviceModel
    recordedAt
    createdAt
  }
}

mutation CreateGeoEvent($input: GeoEventInput!) {
  createGeoEvent(input: $input) {
    id
    latitude
    longitude
    eventType
    platform
    recordedAt
    createdAt
  }
}
